class Solution:
    def divideString(self, s, k, fill):
        groups = []
        current = []
        for ch in s:
            current.append(ch)
            if len(current) == k:
                groups.append(''.join(current))
                current = []
        if current:
            current.extend([fill] * (k - len(current)))
            groups.append(''.join(current))
        return groups

