class Solution:
    def divideString(self, s, k, fill):
        groups = []
        for i in range(0, len(s), k):
            chunk = s[i:i + k]
            if len(chunk) < k:
                chunk += fill * (k - len(chunk))
            groups.append(chunk)
        return groups

